import CabanaGallery from "./SubComponents/CabañaGallery.jsx";
import Photos from "../data/Fotos.jsx";
import Datos from "./SubComponents/DatosCabaña.jsx";
import { motion } from "motion/react";
import cabañasData from "../data/cabañasData.jsx";

const ChevronLeft = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
    <path d="M15 18l-6-6 6-6" />
  </svg>
);
 
const ChevronRight = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
    <path d="M9 18l6-6-6-6" />
  </svg>
);

const Cabañas = () => {
  return (
    <section className="h-screen snap-start overflow-hidden bg-[#D8C4A5] flex items-center justify-center">
      <div className="w-[60%] max-w-4xl mx-auto">
        
        <motion.div
        initial={{ opacity: 0.7, y: 100 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: false }}
        transition={{ duration: 1.2, ease: "easeOut" }}
      >
        <div className="bg-white rounded-[28px] overflow-hidden flex shadow-[0_8px_48px_rgba(80,40,10,0.13)] h-[75vh]">
          <CabanaGallery photos={Photos} />
          <Datos />
        </div>
       
      </motion.div>
        
      </div>
    </section>
  );
};

export default Cabañas;
